if (!staticData.flights) {
  staticData.flights = [
    { flight_id: 'FL001', origin: 'Cairo', destination: 'Dubai', departure_time: '2026-04-10 10:00', price: 500.00, available_seats: 10 },
    { flight_id: 'FL002', origin: 'Cairo', destination: 'Dubai', departure_time: '2026-04-10 14:00', price: 550.00, available_seats: 5 },
    { flight_id: 'FL003', origin: 'Riyadh', destination: 'Jeddah', departure_time: '2026-04-12 09:00', price: 200.00, available_seats: 20 }
  ];
}

// الكلمة السحرية المباشرة (query)
const origin = query.origin;
const destination = query.destination;

const available = staticData.flights.filter(f => f.origin === origin && f.destination === destination && f.available_seats > 0);
if(available.length === 0) return JSON.stringify({status: 'no_flights_found', message: `لا توجد رحلات متاحة من ${origin} إلى ${destination}.`});
return JSON.stringify({status: 'success', flights: available});

