const staticData = $getWorkflowStaticData('global');

// حقن الداتا بيز مباشرة لتجنب مشاكل وضع التيست
if (!staticData.flights) {
  staticData.flights = [
    { flight_id: 'FL001', origin: 'Cairo', destination: 'Dubai', departure_time: '2026-04-10 10:00', price: 500.00, available_seats: 10 },
    { flight_id: 'FL002', origin: 'Cairo', destination: 'Dubai', departure_time: '2026-04-10 14:00', price: 550.00, available_seats: 5 },
    { flight_id: 'FL003', origin: 'Riyadh', destination: 'Jeddah', departure_time: '2026-04-12 09:00', price: 200.00, available_seats: 20 }
  ];
}

// سحب رقم الرحلة وتحويله لحروف كبيرة عشان يتطابق مع الداتا بيز
const flight_id = query.flight_id.toUpperCase();

// البحث عن الرحلة
const flight = staticData.flights.find(f => f.flight_id === flight_id);

if (!flight) {
  return JSON.stringify({status: 'error', message: 'رقم الرحلة غير صحيح.'});
}

if (flight.available_seats <= 0) {
  return JSON.stringify({status: 'error', message: 'عذراً، هذه الرحلة ممتلئة ولا توجد مقاعد متاحة.'});
}

// تنفيذ الحجز (تقليل الكراسي)
flight.available_seats -= 1;
return JSON.stringify({status: 'success', message: `تم حجز الرحلة ${flight_id} بنجاح! تم تأكيد مقعدك.`});

